// MARK: - Native Bridge
private final class NativeBridge: NSObject, WKScriptMessageHandler {
    weak var hostController: HybridWebViewController?
    var allowedHosts: Set<String> = []

    private var products: [String: SKProduct] = [:]
    private var productsRequest: SKProductsRequest?
    private var purchaseCallbackId: String?
    private var purchaseProductId: String?

    override init() {
        super.init()
        SKPaymentQueue.default().add(self)
    }

    deinit {
        SKPaymentQueue.default().remove(self)
        productsRequest?.cancel()
    }

    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard let host = hostController else { return }

        if !allowedHosts.isEmpty {
            guard let frameURL = host.webView.url, let frameHost = frameURL.host?.lowercased(), allowedHosts.contains(frameHost) else {
                return
            }
        }

        guard let body = message.body as? [String: Any] else { return }
        let action = (body["action"] as? String) ?? ""
        let params = (body["params"] as? [String: Any]) ?? [:]
        let callbackId = (body["callbackId"] as? String) ?? ""

        switch action {
        case "camera.requestPermission":
            handleCameraPermission(callbackId: callbackId)

        case "push.requestPermission":
            handlePushPermission(callbackId: callbackId)

        case "push.getStatus":
            handlePushStatus(callbackId: callbackId)

        case "iap.canMakePayments":
            handleCanMakePayments(callbackId: callbackId)

        case "iap.fetchProducts":
            handleFetchProducts(params: params, callbackId: callbackId)

        case "iap.purchase":
            handlePurchase(params: params, callbackId: callbackId)

        case "iap.restore":
            handleRestore(callbackId: callbackId)

        case "app.openURL":
            handleOpenURL(params: params, callbackId: callbackId)

        case "app.getDeviceInfo":
            handleDeviceInfo(callbackId: callbackId)

        default:
            host.errorToWeb(callbackId: callbackId, code: "unknown_action", message: "Unknown action: \(action)")
        }
    }

    private func handleCameraPermission(callbackId: String) {
        guard let host = hostController else { return }
        AVCaptureDevice.requestAccess(for: .video) { granted in
            DispatchQueue.main.async {
                host.respondToWeb(callbackId: callbackId, result: ["granted": granted])
            }
        }
    }

    private func handlePushPermission(callbackId: String) {
        guard let host = hostController else { return }
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { granted, err in
            DispatchQueue.main.async {
                if let err = err {
                    host.errorToWeb(callbackId: callbackId, code: "push_auth_error", message: err.localizedDescription)
                } else {
                    UIApplication.shared.registerForRemoteNotifications()
                    host.respondToWeb(callbackId: callbackId, result: ["granted": granted])
                }
            }
        }
    }

    private func handlePushStatus(callbackId: String) {
        guard let host = hostController else { return }
        UNUserNotificationCenter.current().getNotificationSettings { settings in
            DispatchQueue.main.async {
                host.respondToWeb(callbackId: callbackId, result: [
                    "authorizationStatus": settings.authorizationStatus.rawValue,
                    "alertSetting": settings.alertSetting.rawValue,
                    "soundSetting": settings.soundSetting.rawValue,
                    "badgeSetting": settings.badgeSetting.rawValue
                ])
            }
        }
    }

    private func handleCanMakePayments(callbackId: String) {
        hostController?.respondToWeb(callbackId: callbackId, result: ["canMakePayments": SKPaymentQueue.canMakePayments()])
    }

    private func handleFetchProducts(params: [String: Any], callbackId: String) {
        guard let host = hostController else { return }
        let ids = (params["productIds"] as? [String]) ?? []
        guard !ids.isEmpty else {
            host.errorToWeb(callbackId: callbackId, code: "invalid_params", message: "productIds is required")
            return
        }

        productsRequest?.cancel()
        let request = SKProductsRequest(productIdentifiers: Set(ids))
        productsRequest = request
        let delegate = ProductsRequestDelegate { [weak self] response, error in
            guard let self else { return }
            DispatchQueue.main.async {
                if let error = error {
                    host.errorToWeb(callbackId: callbackId, code: "iap_products_error", message: error.localizedDescription)
                    return
                }
                guard let response = response else {
                    host.errorToWeb(callbackId: callbackId, code: "iap_products_error", message: "No response")
                    return
                }
                for p in response.products {
                    self.products[p.productIdentifier] = p
                }
                let productsPayload: [[String: Any]] = response.products.map { p in
                    [
                        "productId": p.productIdentifier,
                        "localizedTitle": p.localizedTitle,
                        "localizedDescription": p.localizedDescription,
                        "price": p.price.stringValue,
                        "priceLocale": p.priceLocale.identifier
                    ]
                }
                host.respondToWeb(callbackId: callbackId, result: [
                    "products": productsPayload,
                    "invalidProductIds": response.invalidProductIdentifiers
                ])
            }
        }
        request.delegate = delegate
        objc_setAssociatedObject(request, Unmanaged.passUnretained(request).toOpaque(), delegate, .OBJC_ASSOCIATION_RETAIN_NONATOMIC)
        request.start()
    }

    private func handlePurchase(params: [String: Any], callbackId: String) {
        guard let host = hostController else { return }
        guard SKPaymentQueue.canMakePayments() else {
            host.errorToWeb(callbackId: callbackId, code: "iap_unavailable", message: "In-app purchases not available")
            return
        }
        guard purchaseCallbackId == nil else {
            host.errorToWeb(callbackId: callbackId, code: "iap_busy", message: "Another purchase is in progress")
            return
        }
        guard let productId = params["productId"] as? String, !productId.isEmpty else {
            host.errorToWeb(callbackId: callbackId, code: "invalid_params", message: "productId is required")
            return
        }
        guard let product = products[productId] else {
            host.errorToWeb(callbackId: callbackId, code: "iap_product_not_fetched", message: "Product not fetched. Call iap.fetchProducts first.")
            return
        }

        purchaseCallbackId = callbackId
        purchaseProductId = productId
        let payment = SKPayment(product: product)
        SKPaymentQueue.default().add(payment)
    }

    private func handleRestore(callbackId: String) {
        guard let host = hostController else { return }
        guard purchaseCallbackId == nil else {
            host.errorToWeb(callbackId: callbackId, code: "iap_busy", message: "Another purchase is in progress")
            return
        }
        purchaseCallbackId = callbackId
        purchaseProductId = nil
        SKPaymentQueue.default().restoreCompletedTransactions()
    }

    private func handleOpenURL(params: [String: Any], callbackId: String) {
        guard let host = hostController else { return }
        guard let urlString = params["url"] as? String, let url = URL(string: urlString) else {
            host.errorToWeb(callbackId: callbackId, code: "invalid_params", message: "url is required")
            return
        }
        UIApplication.shared.open(url, options: [:]) { success in
            host.respondToWeb(callbackId: callbackId, result: ["success": success])
        }
    }

    private func handleDeviceInfo(callbackId: String) {
        guard let host = hostController else { return }
        let device = UIDevice.current
        let info: [String: Any] = [
            "systemName": device.systemName,
            "systemVersion": device.systemVersion,
            "model": device.model,
            "localizedModel": device.localizedModel,
            "identifierForVendor": device.identifierForVendor?.uuidString as Any
        ]
        host.respondToWeb(callbackId: callbackId, result: info)
    }

    private final class ProductsRequestDelegate: NSObject, SKProductsRequestDelegate {
        let completion: (SKProductsResponse?, Error?) -> Void
        init(completion: @escaping (SKProductsResponse?, Error?) -> Void) { self.completion = completion }
        func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) { completion(response, nil) }
        func request(_ request: SKRequest, didFailWithError error: Error) { completion(nil, error) }
        func requestDidFinish(_ request: SKRequest) { }
    }
}

// MARK: - StoreKit Transaction Observer
extension NativeBridge: SKPaymentTransactionObserver {
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        guard let host = hostController else { return }

        for t in transactions {
            switch t.transactionState {
            case .purchasing, .deferred:
                break

            case .purchased:
                let cb = purchaseCallbackId
                let pid = t.payment.productIdentifier
                if let cb {
                    host.respondToWeb(callbackId: cb, result: [
                        "status": "purchased",
                        "productId": pid,
                        "transactionId": t.transactionIdentifier as Any,
                        "originalTransactionId": t.original?.transactionIdentifier as Any
                    ])
                }
                purchaseCallbackId = nil
                purchaseProductId = nil
                queue.finishTransaction(t)

            case .restored:
                let cb = purchaseCallbackId
                if let cb {
                    host.respondToWeb(callbackId: cb, result: [
                        "status": "restored",
                        "productId": t.payment.productIdentifier,
                        "transactionId": t.transactionIdentifier as Any,
                        "originalTransactionId": t.original?.transactionIdentifier as Any
                    ])
                }
                purchaseCallbackId = nil
                purchaseProductId = nil
                queue.finishTransaction(t)

            case .failed:
                let cb = purchaseCallbackId
                let error = t.error as NSError?
                let isCancelled = (error?.domain == SKErrorDomain && error?.code == SKError.paymentCancelled.rawValue)
                if let cb {
                    host.errorToWeb(callbackId: cb,
                                    code: isCancelled ? "iap_cancelled" : "iap_failed",
                                    message: error?.localizedDescription ?? "Purchase failed",
                                    details: [
                                        "productId": t.payment.productIdentifier,
                                        "errorDomain": error?.domain as Any,
                                        "errorCode": error?.code as Any
                                    ])
                }
                purchaseCallbackId = nil
                purchaseProductId = nil
                queue.finishTransaction(t)

            @unknown default:
                break
            }
        }
    }

    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        guard let host = hostController else { return }
        if let cb = purchaseCallbackId {
            host.respondToWeb(callbackId: cb, result: ["status": "restore_finished"])
            purchaseCallbackId = nil
            purchaseProductId = nil
        }
    }

    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        guard let host = hostController else { return }
        if let cb = purchaseCallbackId {
            host.errorToWeb(callbackId: cb, code: "iap_restore_failed", message: error.localizedDescription)
            purchaseCallbackId = nil
            purchaseProductId = nil
        }
    }
}